    15	                .t_ws()
    16	                // "her" is also a possessive determiner as in "she brandished her sword"
    17	                // "it" and "them" can refer to objects as in "draw your sword(s) and brandish it/them"
    18	                .then_kind_except(TokenKind::is_object_pronoun, &["her", "it", "them"]),
    19	        }
    20	    }
