    30	    fn match_to_lint(&self, toks: &[Token], src: &[char]) -> Option<Lint> {
    31	        let verb_span = toks.first()?.span;
    32	        let verb_chars = verb_span.get_content(src);
    33	
    34	        enum Form {
    35	            Base,
    36	            Past,
    37	            ThirdPerson,
    38	            Ing,
    39	        }
    40	
    41	        let infl = match verb_chars.last().map(|c| c.to_ascii_lowercase()) {
    42	            Some('h') => Form::Base,
    43	            Some('d') => Form::Past,
    44	            Some('s') => Form::ThirdPerson,
    45	            Some('g') => Form::Ing,
    46	            _ => return None,
    47	        };
    48	
    49	        Some(Lint {
    50	            span: verb_span,
    51	            lint_kind: LintKind::Malapropism,
    52	            suggestions: vec![Suggestion::replace_with_match_case_str(
    53	                match infl {
    54	                    Form::Base => "brand",
    55	                    Form::Past => "branded",
    56	                    Form::ThirdPerson => "brands",
    57	                    Form::Ing => "branding",
    58	                },
    59	                verb_chars,
    60	            )],
    61	            message: "`Brandish` means to wield a weapon. You probably mean `brand`.".to_string(),
    62	            ..Default::default()
    63	        })
    64	    }
    65	
    66	    fn description(&self) -> &str {
    67	        "Looks for `brandish` wrongly used when `brand` is intended."
    68	    }
