    10	impl Default for QuiteQuiet {
    11	    fn default() -> Self {
    12	        let quiet_word = SequenceExpr::default()
    13	            .t_aco("quiet")
    14	            .t_ws()
    15	            .then_kind_any_but_not_except(
    16	                &[
    17	                    TokenKind::is_adjective,
    18	                    TokenKind::is_adverb,
    19	                    TokenKind::is_verb,
    20	                ] as &[_],
    21	                TokenKind::is_noun,
    22	                &["here", "up"],
    23	            );
    24	
    25	        let negative_contraction_quiet = SequenceExpr::with(|tok: &Token, src: &[char]| {
    26	            if !tok.kind.is_verb() || !tok.kind.is_apostrophized() {
    27	                return false;
    28	            }
    29	            tok.span
    30	                .get_content(src)
    31	                .ends_with_any_ignore_ascii_case_chars(&[&['n', '\'', 't'], &['n', '’', 't']])
    32	        })
    33	        .t_ws()
    34	        .t_aco("quiet");
    35	
    36	        let adverb_quite = SequenceExpr::default()
    37	            .then_kind_except(
    38	                TokenKind::is_adverb,
    39	                &["actually", "never", "not", "really", "generally"],
    40	            )
    41	            .t_ws()
    42	            .t_aco("quite");
    43	
    44	        Self {
    45	            expr: FirstMatchOf::new(vec![
    46	                Box::new(quiet_word),
    47	                Box::new(negative_contraction_quiet),
    48	                Box::new(adverb_quite),
    49	            ]),
    50	        }
    51	    }
    52	}
