    71	                    "quiet".chars().collect(),
    72	                    quite_span.get_content(src),
    73	                )],
    74	                message: "‘Quite’ might be a typo here. It means ‘rather’ but you might be trying to say ‘quiet’ (not noisy).".to_string(),
    75	                priority: 63,
    76	            });
    77	        } else if text.starts_with("quiet") {
    78	            let quiet_span = toks.first()?.span;
    79	
    80	            return Some(Lint {
    81	                span: quiet_span,
    82	                lint_kind: LintKind::Typo,
    83	                suggestions: vec![Suggestion::replace_with_match_case(
    84	                    "quite".chars().collect(),
    85	                    quiet_span.get_content(src),
    86	                )],
    87	                message: "‘Quiet’ might be a typo here. It means ‘not noisy’ but you might be trying to say ‘quite’ (rather).".to_string(),
    88	                priority: 63,
    89	            });
    90	        } else if text.ends_with("quiet") {
