use crate::expr::{Expr, SequenceExpr};
use crate::linting::expr_linter::Chunk;
use crate::linting::{ExprLinter, Lint, LintKind, Suggestion};
use crate::{CharStringExt, Token, TokenStringExt};

pub struct FlauntFlout {
    expr: SequenceExpr,
}

impl Default for FlauntFlout {
    fn default() -> Self {
        let pattern = SequenceExpr::word_set(&["flaunt", "flaunts", "flaunted", "flaunting"])
            .then_whitespace()
            .then_word_set(&[
                "the", "any", "all", "basic", "every", "federal", "international", "local",
                "these", "those", "our",
            ])
            .then_whitespace()
            .then_word_set(&[
                "law", "laws", "rule", "rules", "regulation", "regulations", "statute",
                "statutes", "ordinance", "ordinances", "constitution", "protocol",
                "protocols", "guideline", "guidelines", "code", "codes",
            ]);

        Self { expr: pattern }
    }
}

impl FlauntFlout {
    fn to_correct(word: &str) -> &str {
        match word.to_lowercase().as_str() {
            "flaunt" => "flout",
            "flaunts" => "flouts",
            "flaunted" => "flouted",
            "flaunting" => "flouting",
            _ => word,
        }
    }
}

impl ExprLinter for FlauntFlout {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        &self.expr
    }

    fn match_to_lint(&self, matched_tokens: &[Token], source: &[char]) -> Option<Lint> {
        let flaunt_span = matched_tokens.first()?.span;
        let flaunt_word = flaunt_span.get_content_string(source).to_lowercase();
        let correct = Self::to_correct(&flaunt_word);

        Some(Lint {
            span: flaunt_span,
            lint_kind: LintKind::WordChoice,
            suggestions: vec![Suggestion::replace_with_match_case_str(
                correct,
                flaunt_span.get_content(source),
