        let has_rule_word = after.iter().any(|tok| {
            tok.kind.is_word()
                && RULE_WORDS
                    .iter()
                    .any(|&rw| tok.span.get_content(source).eq_ignore_ascii_case_str(rw))
        });

        if !has_rule_word {
            return None;
