use crate::expr::{Expr, SequenceExpr};
use crate::linting::expr_linter::Chunk;
use crate::linting::{ExprLinter, Lint, LintKind, Suggestion};
use crate::{CharStringExt, Token, TokenStringExt};

/// Words that indicate the "flout" meaning (rules, laws, etc.)
const RULE_WORDS: &[&str] = &[
    "law", "laws", "rule", "rules", "regulation", "regulations", "statute",
    "statutes", "ordinance", "ordinances", "constitution", "protocol",
    "protocols", "guideline", "guidelines", "code", "codes",
];

pub struct FlauntFlout {
    expr: SequenceExpr,
}

impl Default for FlauntFlout {
    fn default() -> Self {
        let pattern = SequenceExpr::word_set(&["flaunt", "flaunts", "flaunted", "flaunting"]);

        Self { expr: pattern }
    }
}

impl FlauntFlout {
    fn to_correct(word: &str) -> &str {
        match word.to_lowercase().as_str() {
            "flaunt" => "flout",
            "flaunts" => "flouts",
            "flaunted" => "flouted",
            "flaunting" => "flouting",
            _ => word,
        }
    }
}

impl ExprLinter for FlauntFlout {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        &self.expr
    }

    fn match_to_lint_with_context(
        &self,
        matched_tokens: &[Token],
        source: &[char],
        context: Option<(&[Token], &[Token])>,
    ) -> Option<Lint> {
        let flaunt_token = matched_tokens.first()?;
        let flaunt_span = flaunt_token.span;
        let flaunt_word = flaunt_span.get_content_string(source).to_lowercase();
        let correct = Self::to_correct(&flaunt_word);

        // Check if any rule/law word appears after the flaunt token in the same chunk
        let (_, after) = context?;
        let has_rule_word = after.iter().any(|tok| {
            tok.kind.is_word()
                && RULE_WORDS
                    .iter()
                    .any(|&rw| tok.span.get_content(source).eq_ignore_ascii_case_str(rw))
        });

        if !has_rule_word {
            return None;
        }

        Some(Lint {
            span: flaunt_span,
            lint_kind: LintKind::WordChoice,
            suggestions: vec![Suggestion::replace_with_match_case_str(
                correct,
                flaunt_span.get_content(source),
            )],
            message: format!(
                "`Flaunt` means to show off. Did you mean `{correct}` (to openly disregard rules)?",
            ),
            priority: 31,
        })
    }

    fn description(&self) -> &str {
        "Detects incorrect usage of `flaunt` (to show off) when `flout` (to openly disregard rules) is intended, as in `flout the rules`."
    }
}

#[cfg(test)]
mod tests {
    use super::FlauntFlout;
    use crate::linting::tests::assert_suggestion_result;

    #[test]
    fn corrects_flaunted_laws() {
        assert_suggestion_result(
            "He flaunted US bankruptcy laws for personal gain.",
            FlauntFlout::default(),
            "He flouted US bankruptcy laws for personal gain.",
        );
    }

    #[test]
    fn corrects_flaunts_the_rules() {
        assert_suggestion_result(
            "It's got a Kirk-esque captain who flaunts the rules in favour of 'getting her done'.",
            FlauntFlout::default(),
            "It's got a Kirk-esque captain who flouts the rules in favour of 'getting her done'.",
        );
    }

    #[test]
    fn corrects_flaunting_the_laws() {
        assert_suggestion_result(
            "That's what deranged scientists flaunting the laws of God and Man are for",
            FlauntFlout::default(),
            "That's what deranged scientists flouting the laws of God and Man are for",
        );
    }

    #[test]
    fn corrects_flaunt_basic_rules() {
        assert_suggestion_result(
            "some seem to flaunt the basic rules of punctuation and grammar.",
            FlauntFlout::default(),
            "some seem to flout the basic rules of punctuation and grammar.",
        );
    }

    #[test]
    fn corrects_flaunt_the_law() {
        assert_suggestion_result(
            "They continue to flaunt the law with impunity.",
            FlauntFlout::default(),
            "They continue to flout the law with impunity.",
        );
    }

    #[test]
    fn does_not_correct_correct_flaunt_usage() {
        assert_suggestion_result(
            "She loved to flaunt her wealth at parties.",
            FlauntFlout::default(),
            "She loved to flaunt her wealth at parties.",
        );
    }
}

